import { memo } from 'react';

interface UserCardProps {
  name: string;
  avatar: string;
}

const UserCard = memo(function UserCard({ name, avatar }: UserCardProps) {
  console.log('UserCard renderizou');
  return (
    <div className="card">
      <img src={avatar} alt={name} />
      <h3>{name}</h3>
    </div>
  );
});

export default UserCard;

// ❌ Memo quebrado: handleClick é recriado a cada render
function Parent() {
  const [count, setCount] = useState(0);

  return (
    <>
      <button onClick={() => setCount(c => c + 1)}>+</button>
      <UserCard
        name="Ana"
        avatar="/ana.jpg"
        onClick={() => console.log('clicou')}  // nova ref!
      />
    </>
  );
}

// ✅ Memo preservado: useCallback estabiliza a referência
function Parent() {
  const [count, setCount] = useState(0);

  const handleClick = useCallback(() => {
    console.log('clicou');
  }, []);

  return (
    <>
      <button onClick={() => setCount(c => c + 1)}>+</button>
      <UserCard name="Ana" avatar="/ana.jpg" onClick={handleClick} />
    </>
  );
}
